def normalize_users(users):
    if not users:
        return []
    values = [users] if isinstance(users, str) else users
    normalized = []
    for user in values:
        if user is None:
            continue
        for comma_part in str(user).split(","):
            normalized.extend(comma_part.split(";"))
    return list(dict.fromkeys(user.strip() for user in normalized if user and user.strip()))


def build_person_index_objs(risk_person_index_model, risk, now):
    objs = []
    for field_name, relation_type in PERSON_RELATION_FIELDS.items():
        for user in normalize_users(getattr(risk, field_name, None)):
            objs.append(
                risk_person_index_model(
                    risk_id=risk.risk_id,
                    relation_type=relation_type,
                    user=user,
                    created_at=now,
                    updated_at=now,
                )
            )
    return objs


def process_batch(risk_person_index_model, batch, db_alias):
    now = timezone.now()
    person_index_creates = []

    for risk in batch:
        person_index_creates.extend(build_person_index_objs(risk_person_index_model, risk, now))

    if person_index_creates:
        risk_person_index_model.objects.using(db_alias).bulk_create(
            person_index_creates, batch_size=BATCH_SIZE, ignore_conflicts=True
        )

    return len(batch), len(person_index_creates)


def format_progress(processed, expected):
    if not expected:
        return str(processed)
    percent = processed * 100 / expected
    return f"{processed}/{expected} ({percent:.1f}%)"


def backfill_risk_level_snapshots(risk_model, strategy_model, schema_editor):
    """
    风险等级快照用单条 SQL 回填。

    这里刻意不通过 ORM 分批 bulk_update：
    - 风险行接近百万级时，Python 对象构造和多轮 UPDATE 成本高；
    - 该 RunPython 在 risk_level 相关索引创建前执行，避免边更新边维护新增索引；
    - LEFT JOIN 能覆盖历史孤儿 strategy_id，孤儿风险等级置空、排序值置为 -1。
    """

