    quote_name = schema_editor.connection.ops.quote_name
    risk_table = quote_name(risk_model._meta.db_table)
    strategy_table = quote_name(strategy_model._meta.db_table)
    risk_count = risk_model.objects.using(db_alias).count()
    now = timezone.now()
    started_at = time.monotonic()

    print(
        "[backfill_risk_level_snapshots] "
        f"start risks={risk_count}, risk_table={risk_model._meta.db_table}, "
        f"strategy_table={strategy_model._meta.db_table}",
        flush=True,
    )

    with schema_editor.connection.cursor() as cursor:
        cursor.execute(
            f"""
            UPDATE {risk_table} AS risk
            LEFT JOIN {strategy_table} AS strategy
                ON risk.{quote_name("strategy_id")} = strategy.{quote_name("strategy_id")}
            SET
                risk.{quote_name("risk_level")} = strategy.{quote_name("risk_level")},
                risk.{quote_name("risk_level_order")} = CASE strategy.{quote_name("risk_level")}
                    WHEN 'LOW' THEN {MigrationRiskLevelOrder.LOW.value}
                    WHEN 'MIDDLE' THEN {MigrationRiskLevelOrder.MIDDLE.value}
                    WHEN 'HIGH' THEN {MigrationRiskLevelOrder.HIGH.value}
                    ELSE {DEFAULT_RISK_LEVEL_ORDER}
                END,
                risk.{quote_name("updated_at")} = %s
            """,
            [now],
        )
    print(
        f"[backfill_risk_level_snapshots] done risks={risk_count}, elapsed={time.monotonic() - started_at:.1f}s",
        flush=True,
    )
