def backfill_person_indexes(risk_model, risk_person_index_model, db_alias, expected_risks=None):
    """
    人员索引仍需解析 JSON，保留 Python 分批插入。

    该步骤在 RiskPersonIndex 索引和唯一约束创建前执行，避免大批量插入时逐行维护二级索引。
    """

    batch = []
    total_risks = 0
    total_person_indexes = 0
    started_at = time.monotonic()
    next_progress_risks = PROGRESS_INTERVAL_RISKS

    print(
        "[backfill_person_indexes] "
        f"start risks={expected_risks or 'unknown'}, batch_size={BATCH_SIZE}, "
        f"progress_interval={PROGRESS_INTERVAL_RISKS}",
        flush=True,
    )

    queryset = (
        risk_model.objects.using(db_alias)
        .only("risk_id", "operator", "current_operator", "notice_users")
        .order_by("risk_id")
    )
    for risk in queryset.iterator(chunk_size=BATCH_SIZE):
        batch.append(risk)
        if len(batch) >= BATCH_SIZE:
            risk_count, person_index_count = process_batch(risk_person_index_model, batch, db_alias)
            total_risks += risk_count
            total_person_indexes += person_index_count
            while total_risks >= next_progress_risks:
                print_person_index_progress(total_risks, expected_risks, total_person_indexes, started_at)
                next_progress_risks += PROGRESS_INTERVAL_RISKS
            batch = []

    if batch:
        risk_count, person_index_count = process_batch(risk_person_index_model, batch, db_alias)
        total_risks += risk_count
        total_person_indexes += person_index_count

    print_person_index_progress(total_risks, expected_risks, total_person_indexes, started_at, prefix="done")
    return total_risks, total_person_indexes


