def has_columns_constraint(constraints, columns, *, unique=None, index=None):
    for constraint in constraints.values():
        if constraint.get("columns") != columns:
            continue
        if unique is not None and constraint.get("unique") != unique:
            continue
        if index is not None and constraint.get("index") != index:
            continue
        return True
    return False


